1	//! The `bench` command — configure an output and measure its achieved rate.
2	//!
3	//! - `bench_binary` / `bench_ascii` configure, measure, and restore.
4	//! - `measure_*` count messages/frames; `report_bench` prints the result;
5	//!   `decode_binary_sample` renders one binary frame.
6	
7	use std::io::{Read, Write};
8	use std::time::{Duration, Instant};
9	
10	use crate::cli::ascii_type_name;
11	use crate::proto::*;
12	use crate::transact::transact_retry;
13	
14	// Binary frame: sync 0xFA, groups=0x01 (Common), one 16-bit field mask, the
15	// selected fields' payload, then a 2-byte CRC. Length depends on the field set.
16	const BENCH_SYNC: u8 = 0xFA;
17	const BENCH_GROUPS: u8 = 0x01;
18	const BENCH_HEADER: usize = 1 + 1 + 2; // sync + groups + field mask
19	const BENCH_CRC: usize = 2;
20	
21	/// A measurement outcome: (count, total wire bytes, elapsed seconds, first sample).
22	type Measured = (u64, u64, f64, Option<String>);
23	
24	/// Read a little-endian f32 from `buf` at `off`.
25	fn rd_f32(buf: &[u8], off: usize) -> f32 {
26	    f32::from_le_bytes(buf[off..off + 4].try_into().unwrap())
27	}
28	
29	/// Human-readable decode of the selected fields in one binary frame.
30	fn decode_binary_sample(frame: &[u8], fields: &[&Field]) -> String {
31	    let mut off = BENCH_HEADER;
32	    let mut parts = Vec::new();
33	    for f in fields {
34	        let s = match f.name {
35	            "time" => format!(
36	                "t={} ns",
37	                u64::from_le_bytes(frame[off..off + 8].try_into().unwrap())
38	            ),
39	            "ypr" => format!(
40	                "ypr=[{:.2}, {:.2}, {:.2}] deg",
41	                rd_f32(frame, off),
42	                rd_f32(frame, off + 4),
43	                rd_f32(frame, off + 8)
44	            ),
45	            "quat" => format!(
46	                "quat=[{:.4}, {:.4}, {:.4}, {:.4}]",
47	                rd_f32(frame, off),
48	                rd_f32(frame, off + 4),
49	                rd_f32(frame, off + 8),
50	                rd_f32(frame, off + 12)
51	            ),
52	            "gyro" => format!(
53	                "gyro=[{:.4}, {:.4}, {:.4}] rad/s",
54	                rd_f32(frame, off),
55	                rd_f32(frame, off + 4),
56	                rd_f32(frame, off + 8)
57	            ),
58	            "accel" => format!(
59	                "accel=[{:.3}, {:.3}, {:.3}] m/s^2",
60	                rd_f32(frame, off),
61	                rd_f32(frame, off + 4),
62	                rd_f32(frame, off + 8)
63	            ),
64	            "imu" => format!(
65	                "uncomp_accel=[{:.3}, {:.3}, {:.3}] uncomp_gyro=[{:.4}, {:.4}, {:.4}]",
66	                rd_f32(frame, off),
67	                rd_f32(frame, off + 4),
68	                rd_f32(frame, off + 8),
69	                rd_f32(frame, off + 12),
70	                rd_f32(frame, off + 16),
71	                rd_f32(frame, off + 20)
72	            ),
73	            "magpres" => format!(
74	                "mag=[{:.3}, {:.3}, {:.3}] G temp={:.2} C pres={:.3} kPa",
75	                rd_f32(frame, off),
76	                rd_f32(frame, off + 4),
77	                rd_f32(frame, off + 8),
78	                rd_f32(frame, off + 12),
79	                rd_f32(frame, off + 16)
80	            ),
81	            _ => "?".to_string(),
82	        };
83	        parts.push(s);
84	        off += f.size;
85	    }
86	    parts.join(", ")
87	}
