151	/// True if `line` is an async data message (a `$VN...` line that isn't a command
152	/// echo or error) with a valid checksum.
153	fn is_async_line(line: &str) -> bool {
154	    line.starts_with("$VN")
155	        && !line.starts_with("$VNRRG")
156	        && !line.starts_with("$VNWRG")
157	        && !line.starts_with("$VNERR")
158	        && verify_checksum(line).is_ok()
159	}
160	
161	/// Measure ASCII async messages for `secs`: counts valid `$VN...` lines and
162	/// their wire bytes, capturing the first as the sample.
163	fn measure_ascii<S: Read>(port: &mut S, secs: u64) -> std::io::Result<Measured> {
164	    let start = Instant::now();
165	    let deadline = start + Duration::from_secs(secs);
166	    let mut buf = [0u8; 1024];
167	    let mut line: Vec<u8> = Vec::new();
168	    let mut msgs = 0u64;
169	    let mut bytes = 0u64;
170	    let mut sample = None;
171	
172	    while Instant::now() < deadline {
173	        let n = match port.read(&mut buf) {
174	            Ok(0) => continue,
175	            Ok(n) => n,
176	            Err(ref e)
177	                if matches!(
178	                    e.kind(),
179	                    std::io::ErrorKind::TimedOut | std::io::ErrorKind::WouldBlock
180	                ) =>
181	            {
182	                continue;
183	            }
184	            Err(e) => return Err(e),
185	        };
186	        for &b in &buf[..n] {
187	            match b {
188	                b'\n' => {
189	                    let raw = String::from_utf8_lossy(&line);
190	                    let cand = match raw.rfind('$') {
191	                        Some(p) => raw[p..].trim(),
192	                        None => raw.trim(),
193	                    };
194	                    if is_async_line(cand) {
195	                        msgs += 1;
196	                        bytes += cand.len() as u64 + 2; // + CRLF
197	                        if sample.is_none() {
198	                            sample = Some(cand.to_string());
199	                        }
200	                    }
201	                    line.clear();
202	                }
203	                b'\r' => {}
204	                _ => {
205	                    line.push(b);
206	                    if line.len() > 1024 {
207	                        line.clear();
208	                    }
209	                }
210	            }
211	        }
212	    }
213	
214	    Ok((msgs, bytes, start.elapsed().as_secs_f64(), sample))
215	}
216	
217	/// Print the shared bench result block (rate, sample, wire utilization).
218	fn report_bench(unit: &str, target_hz: u32, m: Measured, baud: u32) {
219	    let (count, bytes, elapsed, sample) = m;
220	    let rate = if elapsed > 0.0 {
221	        count as f64 / elapsed
222	    } else {
223	        0.0
224	    };
225	    println!("\nResult: {count} {unit} in {elapsed:.2}s = {rate:.1} Hz (target {target_hz} Hz).");
226	    if let Some(s) = sample {
227	        println!("Sample: {s}");
228	    }
229	    let bits = if elapsed > 0.0 {
230	        bytes as f64 * 10.0 / elapsed
231	    } else {
232	        0.0
233	    };
234	    let pct = 100.0 * bits / baud as f64;
235	    println!(
236	        "Wire throughput ~{:.0} kbit/s = {:.0}% of the {:.1} kbit/s {baud}-baud link.",
237	        bits / 1000.0,
238	        pct,
239	        baud as f64 / 1000.0
240	    );
241	}
242	
243	/// Configure a binary output (reg 75) with `fields` at `hz`, measure the frame
244	/// rate for `secs`, then restore the prior state.
245	///
246	/// - `serial_port` is the register-75 `asyncMode`: 1 / 2 for one of the
247	///   VN-100's two UARTs, 3 for both. Binary only streams on the UART the host
248	///   is wired to, so this must include that port (the RPi5 TTL header is
249	///   port 2; the RS-232 bench is port 1).
250	pub fn bench_binary<S: Read + Write>(
251	    port: &mut S,
252	    baud: u32,
253	    hz: u32,
254	    secs: u64,
255	    fields: &[&Field],
256	    serial_port: u8,
257	) -> Result<(), Box<dyn std::error::Error>> {
258	    let divisor = 800 / hz; // device IMU base rate is 800 Hz
259	    let mask: u16 = fields.iter().fold(0, |m, f| m | (1u16 << f.bit));
260	    let payload: usize = fields.iter().map(|f| f.size).sum();
261	    let frame_len = BENCH_HEADER + payload + BENCH_CRC;
262	    let names: Vec<&str> = fields.iter().map(|f| f.name).collect();
263	
264	    // Remember the current ASCII async rate so we can put it back.
265	    let prev = transact_retry(
266	        port,
267	        &build_command("VNRRG,07"),
268	        5,
269	        |l| parse_reg07(l).is_some(),
270	        "could not read current async rate",
271	    )?;
272	    let prev_hz = parse_reg07(&prev).unwrap();
273	
274	    // Silence the ASCII async output FIRST, before configuring the binary
275	    // output. The device's fit check (message_size x rate <= baud) runs on the
276	    // reg-75 write against the SUM of the streams on that port, so leaving ASCII
277	    // async running can make the binary config fail with $VNERR 0x0C even when
278	    // the binary stream fits the link on its own. Silencing first also means we
279	    // measure ONLY the binary stream.
280	    transact_retry(
281	        port,
282	        &build_command("VNWRG,07,0"),
283	        5,
284	        |l| parse_reg07(l).is_some(),
285	        "could not disable ASCII async output",
286	    )?;
287	
288	    // Configure Binary Output 1 (reg 75) on the chosen serial port(s). A $VNERR
289	    // here now means the binary stream alone won't fit the current baud. If the
290	    // write fails, restore the ASCII async rate before bailing so we don't leave
291	    // the device with async output switched off.
292	    let cfg = format!("VNWRG,75,{serial_port},{divisor},01,{mask:04X}");
293	    if let Err(e) = transact_retry(
294	        port,
295	        &build_command(&cfg),
296	        5,
297	        |l| l.starts_with("$VNWRG,75"),
298	        "device did not accept the binary config (a $VNERR means it won't fit at this baud)",
299	    ) {
300	        let _ = transact_retry(
301	            port,
302	            &build_command(&format!("VNWRG,07,{prev_hz}")),
303	            3,
304	            |l| parse_reg07(l).is_some(),
305	            "restore: ASCII async rate",
306	        );
307	        return Err(e);
308	    }
309	    println!(
310	        "Configured binary output: Common{names:?} @ {hz} Hz (divisor {divisor}, {frame_len} B/frame)."
311	    );
312	
313	    println!("Measuring for {secs}s...");
314	    let (frames, bytes, elapsed, first) = measure_binary(port, frame_len, secs)?;
315	    let sample = first.map(|fr| decode_binary_sample(&fr, fields));
316	    report_bench("frames", hz, (frames, bytes, elapsed, sample), baud);
317	
318	    // Restore: turn the binary output off, put the ASCII rate back.
319	    let _ = transact_retry(
320	        port,
321	        &build_command(&format!("VNWRG,75,0,{divisor},01,{mask:04X}")),
322	        3,
323	        |l| l.starts_with("$VNWRG,75"),
324	        "restore: disable binary output",
325	    );
326	    let _ = transact_retry(
327	        port,
328	        &build_command(&format!("VNWRG,07,{prev_hz}")),
329	        3,
330	        |l| parse_reg07(l).is_some(),
331	        "restore: ASCII async rate",
332	    );
333	    println!("Restored: binary output off, ASCII async back to {prev_hz} Hz.");
334	
335	    if frames == 0 {
336	        return Err(
337	            "received 0 binary frames — the config may have targeted the wrong serial port \
338	             (try a VN-100 on serial1), or the device isn't streaming"
339	                .into(),
340	        );
341	    }
342	    Ok(())
343	}
344	
345	/// Set the ASCII async rate (reg 7) to `hz` — and optionally the message type
346	/// (reg 6) — measure the message rate for `secs`, then restore prior state.
347	pub fn bench_ascii<S: Read + Write>(
348	    port: &mut S,
349	    baud: u32,
350	    hz: u32,
351	    secs: u64,
352	    ascii_type: Option<u8>,
353	) -> Result<(), Box<dyn std::error::Error>> {
354	    let prev = transact_retry(
355	        port,
356	        &build_command("VNRRG,07"),
357	        5,
358	        |l| parse_reg07(l).is_some(),
359	        "could not read current async rate",
360	    )?;
361	    let prev_hz = parse_reg07(&prev).unwrap();
362	
363	    // Optionally switch the ASCII message type (register 6), remembering the
364	    // previous value to restore it.
365	    let prev_type = if let Some(t) = ascii_type {
366	        let r = transact_retry(
367	            port,
368	            &build_command("VNRRG,06"),
369	            5,
370	            |l| parse_reg06(l).is_some(),
371	            "could not read current ASCII type",
372	        )?;
373	        let prev_t = parse_reg06(&r).unwrap();
374	        transact_retry(
375	            port,
376	            &build_command(&format!("VNWRG,06,{t}")),
377	            5,
378	            |l| l.starts_with("$VNWRG,06"),
379	            "device did not accept the ASCII type (register 6)",
380	        )?;
381	        println!("Set ASCII type to {} (ADOR {t}).", ascii_type_name(t));
382	        Some(prev_t)
383	    } else {
384	        None
385	    };
386	
387	    // A $VNERR here means the ASCII message doesn't fit at this baud/rate.
388	    transact_retry(
389	        port,
390	        &build_command(&format!("VNWRG,07,{hz}")),
391	        5,
392	        |l| parse_reg07(l).is_some(),
393	        "device did not accept the async rate (a $VNERR means the message won't fit at this baud)",
394	    )?;
395	    println!("Set ASCII async rate to {hz} Hz; measuring the $VN message stream for {secs}s...");
396	
397	    let measured = measure_ascii(port, secs)?;
398	    let msgs = measured.0;
399	    report_bench("messages", hz, measured, baud);
400	
401	    let _ = transact_retry(
402	        port,
403	        &build_command(&format!("VNWRG,07,{prev_hz}")),
404	        3,
405	        |l| parse_reg07(l).is_some(),
406	        "restore: ASCII async rate",
407	    );
408	    if let Some(pt) = prev_type {
409	        let _ = transact_retry(
410	            port,
411	            &build_command(&format!("VNWRG,06,{pt}")),
412	            3,
413	            |l| l.starts_with("$VNWRG,06"),
414	            "restore: ASCII type",
415	        );
416	        println!(
417	            "Restored: ASCII async back to {prev_hz} Hz, type {}.",
418	            ascii_type_name(pt)
419	        );
420	    } else {
421	        println!("Restored: ASCII async back to {prev_hz} Hz.");
422	    }
423	
424	    if msgs == 0 {
425	        return Err(
426	            "received 0 async messages — is async output (register 6) on, or is the port wrong?"
427	                .into(),
428	        );
429	    }
430	    Ok(())
431	}
