14	// Binary frame: sync 0xFA, groups=0x01 (Common), one 16-bit field mask, the
15	// selected fields' payload, then a 2-byte CRC. Length depends on the field set.
16	const BENCH_SYNC: u8 = 0xFA;
17	const BENCH_GROUPS: u8 = 0x01;
18	const BENCH_HEADER: usize = 1 + 1 + 2; // sync + groups + field mask
19	const BENCH_CRC: usize = 2;
20	
21	/// A measurement outcome: (count, total wire bytes, elapsed seconds, first sample).
22	type Measured = (u64, u64, f64, Option<String>);
23	
24	/// Read a little-endian f32 from `buf` at `off`.
25	fn rd_f32(buf: &[u8], off: usize) -> f32 {
26	    f32::from_le_bytes(buf[off..off + 4].try_into().unwrap())
27	}
28	
29	/// Human-readable decode of the selected fields in one binary frame.
30	fn decode_binary_sample(frame: &[u8], fields: &[&Field]) -> String {
31	    let mut off = BENCH_HEADER;
32	    let mut parts = Vec::new();
33	    for f in fields {
34	        let s = match f.name {
35	            "time" => format!(
36	                "t={} ns",
37	                u64::from_le_bytes(frame[off..off + 8].try_into().unwrap())
38	            ),
39	            "ypr" => format!(
40	                "ypr=[{:.2}, {:.2}, {:.2}] deg",
41	                rd_f32(frame, off),
42	                rd_f32(frame, off + 4),
43	                rd_f32(frame, off + 8)
44	            ),
45	            "quat" => format!(
46	                "quat=[{:.4}, {:.4}, {:.4}, {:.4}]",
47	                rd_f32(frame, off),
48	                rd_f32(frame, off + 4),
49	                rd_f32(frame, off + 8),
50	                rd_f32(frame, off + 12)
51	            ),
52	            "gyro" => format!(
53	                "gyro=[{:.4}, {:.4}, {:.4}] rad/s",
54	                rd_f32(frame, off),
55	                rd_f32(frame, off + 4),
56	                rd_f32(frame, off + 8)
57	            ),
58	            "accel" => format!(
