89	/// Measure binary frames of `frame_len` bytes for `secs`. Counts CRC-valid
90	/// frames and captures the first frame's raw bytes for the caller to decode.
91	fn measure_binary<S: Read>(
92	    port: &mut S,
93	    frame_len: usize,
94	    secs: u64,
95	) -> std::io::Result<(u64, u64, f64, Option<Vec<u8>>)> {
96	    let start = Instant::now();
97	    let deadline = start + Duration::from_secs(secs);
98	    let mut buf = [0u8; 1024];
99	    let mut acc: Vec<u8> = Vec::new();
100	    let mut frames = 0u64;
101	    let mut first: Option<Vec<u8>> = None;
102	
103	    while Instant::now() < deadline {
104	        match port.read(&mut buf) {
105	            Ok(0) => continue,
106	            Ok(n) => acc.extend_from_slice(&buf[..n]),
107	            Err(ref e)
108	                if matches!(
109	                    e.kind(),
110	                    std::io::ErrorKind::TimedOut | std::io::ErrorKind::WouldBlock
111	                ) =>
112	            {
113	                continue;
114	            }
115	            Err(e) => return Err(e),
116	        }
117	
118	        let mut i = 0;
119	        while i + frame_len <= acc.len() {
120	            if acc[i] != BENCH_SYNC || acc[i + 1] != BENCH_GROUPS {
121	                i += 1;
122	                continue;
123	            }
124	            let frame = &acc[i..i + frame_len];
125	            // CRC over everything after the sync byte (groups..payload..crc) == 0.
126	            if vn_crc16(&frame[1..]) == 0 {
127	                frames += 1;
128	                if first.is_none() {
129	                    first = Some(frame.to_vec());
130	                }
131	                i += frame_len;
132	            } else {
133	                i += 1; // false sync (0xFA can appear in payload); resync
134	            }
135	        }
136	        acc.drain(0..i);
137	        if acc.len() > 8192 {
138	            let keep = acc.len() - frame_len;
139	            acc.drain(0..keep);
140	        }
141	    }
142	
143	    Ok((
144	        frames,
145	        frames * frame_len as u64,
146	        start.elapsed().as_secs_f64(),
147	        first,
148	    ))
149	}
