1	//! `rw-vn100` — read and configure a VectorNav VN-100 IMU over serial.
2	//!
3	//! The VN-100 speaks an ASCII protocol over a serial port. Each command is
4	//!
5	//! ```text
6	//! $<payload>*XX\r\n
7	//! ```
8	//!
9	//! where `XX` is the 8-bit XOR checksum of every character of `<payload>`
10	//! (i.e. everything between `$` and `*`). Replies echo the same form; binary
11	//! outputs (register 75) use a packed frame ending in a 16-bit CRC instead.
12	//!
13	//! Commands implemented here:
14	//!   get-hz / set-hz       read/write the async output rate    (register 7)
15	//!   baud                  change the serial baud rate          (register 5)
16	//!   rrg / wrg             generic read/write of any register   ($VNRRG / $VNWRG)
17	//!   bench                 configure an output (ASCII async by default, or a
18	//!                         binary output with --bin) and measure the achieved
19	//!                         rate, to see what fits a given baud
20	//!   reset / factory-reset reboot / restore defaults            ($VNRST / $VNRFS)
21	//!
22	//! Key VN messages:
23	//!   $VNRRG,<id>*XX          -> $VNRRG,<id>,<f1>,...*YY   (read register)
24	//!   $VNWRG,<id>,<f1>,...*XX  -> echo                     (write register)
25	//!   $VNWNV*XX               -> $VNWNV*YY                 (save all to flash)
26	//!   $VNERR,<code>*XX                                     (error; see error_description)
27	//!
28	//! The async output rate (register 7) is one of a fixed firmware set
29	//! (`VALID_RATES`); a value that's out of range — or too much data for the
30	//! current baud — returns a `$VNERR` (0x0C = insufficient baud rate).
31	//!
32	//! Register/enum/table values are cited to the ICD and vnsdk in REFERENCE.md.
33	
34	use std::time::Duration;
35	
36	mod bench;
37	mod cli;
38	mod proto;
39	mod transact;
40	use bench::*;
41	use cli::*;
42	use proto::*;
43	use transact::*;
44	
45	/// Print the fields of a `$VN(R|W)RG,<id>,<f1>,<f2>...*XX` reply.
46	fn print_reg_fields(reply: &str) {
47	    let body = reply.trim_start_matches('$');
48	    let body = body.split('*').next().unwrap_or(body);
49	    let parts: Vec<&str> = body.split(',').collect();
50	    match parts.as_slice() {
51	        [_, id, fields @ ..] if !fields.is_empty() => {
52	            println!("register {id}: {fields:?}");
53	        }
54	        [_, id] => println!("register {id}: (no fields)"),
55	        _ => println!("(unrecognized reply)"),
56	    }
57	}
58	
59	/// Parse args, open the serial port, and dispatch the requested command.
60	pub fn run() -> Result<(), Box<dyn std::error::Error>> {
61	    let (config, command) = match parse_args(std::env::args().skip(1)) {
62	        Ok(parsed) => parsed,
63	        Err(e) => {
64	            eprintln!("error: {e}\n");
65	            eprint!("{}", help_text());
66	            std::process::exit(2);
67	        }
68	    };
69	
70	    if let Command::Help = command {
71	        print!("{}", help_text());
72	        return Ok(());
73	    }
74	
75	    if let Command::Version = command {
76	        println!("{}", version_line());
77	        return Ok(());
78	    }
79	
80	    // Stamp a bench run with the tool version as its first line, so a captured
81	    // bench log records which build produced the numbers.
82	    if let Command::Bench { .. } = command {
83	        println!("{}", version_line());
84	    }
85	
86	    println!("Opening {} at {} baud...", config.port, config.baud);
87	    let mut port = serialport::new(&config.port, config.baud)
88	        // Short per-read timeout so read_reply re-checks its overall deadline often.
89	        .timeout(Duration::from_millis(250))
90	        .open()?;
91	
92	    // Let the USB-serial chip lock its baud divisor, then drop any open-time
93	    // line noise / partial async frame before the first command. Without this,
94	    // a fresh open at high baud often loses its first query.
95	    std::thread::sleep(Duration::from_millis(150));
96	    let _ = port.clear(serialport::ClearBuffer::Input);
97	
98	    // Shared "we heard nothing usable" hint — usually a baud mismatch.
99	    let no_reply = format!(
100	        "no usable reply from device — is it actually at {} baud? \
101	         (VN-100 factory default is 115200; use --baud to match, or the `baud` command to change it)",
102	        config.baud
103	    );
104	
105	    match command {
106	        Command::Help | Command::Version => unreachable!("handled above"),
107	
108	        Command::GetHz => {
109	            let reply = transact_retry(
110	                &mut port,
111	                &build_command("VNRRG,07"),
112	                5,
113	                |l| parse_reg07(l).is_some(),
114	                &no_reply,
115	            )?;
116	            println!("RX: {reply}");
117	            println!("Async output rate: {} Hz", parse_reg07(&reply).unwrap());
118	        }
119	
120	        Command::SetHz { hz, persist } => {
121	            let reply = transact_retry(
122	                &mut port,
123	                &build_command(&format!("VNWRG,07,{hz}")),
124	                5,
125	                |l| parse_reg07(l).is_some(),
126	                &no_reply,
127	            )?;
128	            println!("RX: {reply}");
129	            println!("Async output rate: {} Hz", parse_reg07(&reply).unwrap());
130	
131	            if persist {
132	                let confirm = transact_retry(
133	                    &mut port,
134	                    &build_command("VNWNV"),
135	                    5,
136	                    |l| l.starts_with("$VNWNV"),
137	                    &no_reply,
138	                )?;
139	                println!("RX: {confirm}");
140	                println!("Settings written to non-volatile memory.");
141	            }
142	        }
143	
144	        Command::SetBaud {
145	            baud: new_baud,
146	            persist,
147	        } => {
148	            // The device replies at the CURRENT baud, then switches to the new one.
149	            let reply = transact_retry(
150	                &mut port,
151	                &build_command(&format!("VNWRG,05,{new_baud}")),
152	                5,
153	                |l| l.starts_with("$VNWRG,05,"),
154	                &no_reply,
155	            )?;
156	            println!("RX: {reply}");
157	            println!("Device acknowledged baud change to {new_baud}.");
158	
159	            // Give the device a moment to reconfigure its UART before we talk at
160	            // the new rate (the vendor SDK waits ~50 ms here), then switch THIS
161	            // connection in place. We switch in-session rather than close/reopen
162	            // not because the device would forget the baud — it holds the RAM
163	            // value across host reconnects — but because each reconnect risks a
164	            // line transient that, at very high baud (e.g. 921600 on an FT232R),
165	            // can wedge the link until a power cycle.
166	            std::thread::sleep(Duration::from_millis(60));
167	            port.set_baud_rate(new_baud)?;
168	            // Drop any bytes that were in flight across the switch.
169	            let _ = port.clear(serialport::ClearBuffer::Input);
170	
171	            println!("Verifying at {new_baud} baud...");
172	            let verify = transact_retry(
173	                &mut port,
174	                &build_command("VNRRG,07"),
175	                5,
176	                |l| parse_reg07(l).is_some(),
177	                "device did not respond at the new baud (a power cycle reverts to the flash baud)",
178	            )?;
179	            println!("RX: {verify}");
180	            println!(
181	                "Verified — device is at {new_baud} baud (async rate {} Hz).",
182	                parse_reg07(&verify).unwrap()
183	            );
184	
185	            if persist {
186	                let confirm = transact_retry(
187	                    &mut port,
188	                    &build_command("VNWNV"),
189	                    5,
190	                    |l| l.starts_with("$VNWNV"),
191	                    "no $VNWNV confirmation at the new baud",
192	                )?;
193	                println!("RX: {confirm}");

