90	/// Compute the VN-100 checksum: XOR of all bytes in `payload`.
91	pub fn checksum(payload: &str) -> u8 {
92	    payload.bytes().fold(0u8, |acc, b| acc ^ b)
93	}
94	
95	/// Build a full command line (including `$`, `*`, checksum and CRLF) from the
96	/// payload that sits between `$` and `*`, e.g. `"VNRRG,07"`.
97	pub fn build_command(payload: &str) -> String {
98	    format!("${}*{:02X}\r\n", payload, checksum(payload))
99	}
100	
101	/// Verify the trailing `*XX` checksum of a received `$...*XX` line.
102	pub fn verify_checksum(line: &str) -> Result<(), String> {
103	    let payload = line.strip_prefix('$').ok_or("reply missing leading '$'")?;
104	    let (payload, sum) = payload
105	        .rsplit_once('*')
106	        .ok_or("reply missing '*' checksum delimiter")?;
107	    let given = u8::from_str_radix(sum.trim(), 16)
108	        .map_err(|_| format!("malformed checksum field {sum:?}"))?;
109	    let actual = checksum(payload);
110	    if given == actual {
111	        Ok(())
112	    } else {
113	        Err(format!(
114	            "checksum mismatch: reply says {given:02X}, computed {actual:02X}"
115	        ))
116	    }
117	}
118	
119	/// Human-readable description of a VN-100 system error code.
120	/// Authoritative: REFERENCE.md "Error responses" (ICD §1.5 Table 1.6; vnsdk Errors.hpp Error).
121	pub fn error_description(code: u8) -> &'static str {
122	    match code {
123	        1 => "hard fault",
124	        2 => "serial buffer overflow",
125	        3 => "invalid checksum",
126	        4 => "invalid command",
127	        5 => "not enough parameters",
128	        6 => "too many parameters",
129	        7 => "invalid parameter",
130	        8 => "invalid register",
131	        9 => "unauthorized access",
132	        10 => "watchdog reset",
133	        11 => "output buffer overflow",
134	        12 => "insufficient baud rate",
135	        255 => "error buffer overflow",
136	        _ => "unknown error",
137	    }
138	}
139	
140	/// Turn a `$VNERR,<code>*XX` line into a readable message. The code is hex.
141	pub fn vnerr_message(line: &str) -> String {
142	    let code = line
143	        .strip_prefix("$VNERR,")
144	        .and_then(|b| b.split('*').next())
145	        .map(str::trim)
146	        .and_then(|c| u8::from_str_radix(c, 16).ok());
147	    match code {
148	        Some(n) => {
149	            let mut msg = format!("device error 0x{n:02X} ({n}): {}", error_description(n));
150	            if n == 12 {
151	                // By far the most likely error when setting a high output rate.
152	                msg.push_str(
153	                    " — the configured async message won't fit at this output rate over the \
154	                     current serial baud; raise the baud (e.g. `baud 921600`) or shorten the \
155	                     async message (register 6)",
156	                );
157	            }
158	            msg
159	        }
