        c,
        Command::SetBinHz {
            hz: 200,
            persist: false
        }
    ));
    // 150 does not divide 800.
    assert!(parse_args(["set-bin-hz=150"].into_iter().map(String::from)).is_err());
    // Bare set-bin-hz needs a value.
    assert!(parse_args(["set-bin-hz"].into_iter().map(String::from)).is_err());
}

